package com.example.organizadoracademico

import android.app.Application
import com.example.organizadoracademico.di.appModules
import org.koin.android.ext.koin.androidContext
import org.koin.core.context.startKoin

class OrganizadorApplication : Application() {
    override fun onCreate() {
        super.onCreate()

        startKoin {
            androidContext(this@OrganizadorApplication)
            modules(appModules)
        }
    }
}

package com.example.organizadoracademico

import android.app.Application
import com.example.organizadoracademico.data.sync.SyncScheduler
import com.example.organizadoracademico.di.appModules
import org.koin.android.ext.koin.androidContext
import org.koin.core.context.startKoin

class OrganizadorApplication : Application() {
    override fun onCreate() {
        super.onCreate()

        val koinApp = startKoin {
            androidContext(this@OrganizadorApplication)
            modules(appModules)
        }

        koinApp.koin.get<SyncScheduler>().schedulePeriodic()
    }
}

package com.example.organizadoracademico.data.local.dao

import androidx.room.Dao
import androidx.room.Insert
import androidx.room.OnConflictStrategy
import androidx.room.Query
import com.example.organizadoracademico.data.local.entities.HorarioEntity
import kotlinx.coroutines.flow.Flow

@Dao
interface HorarioDao {
    @Query("SELECT * FROM horarios WHERE usuarioId = :userId ORDER BY dia, horaInicio ASC")
    fun getAllByUsuario(userId: Int): Flow<List<HorarioEntity>>

    @Insert(onConflict = OnConflictStrategy.REPLACE)
    suspend fun insert(horario: HorarioEntity)

    @Insert(onConflict = OnConflictStrategy.REPLACE)
    suspend fun insertAll(horarios: List<HorarioEntity>)

    @Query("DELETE FROM horarios WHERE usuarioId = :userId")
    suspend fun deleteAllByUsuario(userId: Int)

    @Query("DELETE FROM horarios WHERE id = :id")
    suspend fun deleteById(id: Int)
}

package com.example.organizadoracademico.data.local.dao

import androidx.room.Dao
import androidx.room.Insert
import androidx.room.OnConflictStrategy
import androidx.room.Query
import com.example.organizadoracademico.data.local.entities.HorarioEntity
import kotlinx.coroutines.flow.Flow

@Dao
interface HorarioDao {
    @Query("SELECT * FROM horarios WHERE usuarioId = :userId ORDER BY dia, horaInicio ASC")
    fun getAllByUsuario(userId: Int): Flow<List<HorarioEntity>>

    @Insert(onConflict = OnConflictStrategy.REPLACE)
    suspend fun insert(horario: HorarioEntity)

    @Insert(onConflict = OnConflictStrategy.REPLACE)
    suspend fun insertAndReturnId(horario: HorarioEntity): Long

    @Insert(onConflict = OnConflictStrategy.REPLACE)
    suspend fun insertAll(horarios: List<HorarioEntity>)

    @Query("DELETE FROM horarios WHERE usuarioId = :userId")
    suspend fun deleteAllByUsuario(userId: Int)

    @Query("DELETE FROM horarios WHERE id = :id")
    suspend fun deleteById(id: Int)

    @Query("SELECT * FROM horarios WHERE id = :id LIMIT 1")
    suspend fun getById(id: Int): HorarioEntity?

    @Query("SELECT * FROM horarios WHERE remoteId = :remoteId LIMIT 1")
    suspend fun getByRemoteId(remoteId: Int): HorarioEntity?
}

package com.example.organizadoracademico.data.local.dao

import androidx.room.Dao
import androidx.room.Insert
import androidx.room.OnConflictStrategy
import androidx.room.Query
import androidx.room.Update
import com.example.organizadoracademico.data.local.entities.ImagenEntity
import kotlinx.coroutines.flow.Flow

@Dao
interface ImagenDao {

    @Query("SELECT * FROM imagenes WHERE materiaId = :materiaId AND usuarioId = :userId ORDER BY fecha DESC")
    fun getByMateria(materiaId: Int, userId: Int): Flow<List<ImagenEntity>>


    @Query("SELECT * FROM imagenes WHERE usuarioId = :userId ORDER BY fecha DESC")
    fun getAllByUsuario(userId: Int): Flow<List<ImagenEntity>>

    @Query("SELECT * FROM imagenes WHERE id = :id")
    suspend fun getById(id: Int): ImagenEntity?

    @Insert(onConflict = OnConflictStrategy.REPLACE)
    suspend fun insert(imagen: ImagenEntity)

    @Insert(onConflict = OnConflictStrategy.REPLACE)
    suspend fun insertAll(imagenes: List<ImagenEntity>)

    @Query("DELETE FROM imagenes WHERE usuarioId = :userId")
    suspend fun deleteAllByUsuario(userId: Int)

    @Query("DELETE FROM imagenes WHERE materiaId = :materiaId AND usuarioId = :userId")
    suspend fun deleteByMateriaAndUsuario(materiaId: Int, userId: Int)

    @Update
    suspend fun update(imagen: ImagenEntity)

    @Query("UPDATE imagenes SET nota = :nota WHERE id = :id")
    suspend fun updateNota(id: Int, nota: String)

    @Query("UPDATE imagenes SET favorita = :favorita WHERE id = :id")
    suspend fun toggleFavorita(id: Int, favorita: Boolean)

    @Query("DELETE FROM imagenes WHERE id = :id")
    suspend fun deleteById(id: Int)
}

package com.example.organizadoracademico.data.local.dao

import androidx.room.Dao
import androidx.room.Insert
import androidx.room.OnConflictStrategy
import androidx.room.Query
import androidx.room.Update
import com.example.organizadoracademico.data.local.entities.ImagenEntity
import kotlinx.coroutines.flow.Flow

@Dao
interface ImagenDao {

    @Query("SELECT * FROM imagenes WHERE materiaId = :materiaId AND usuarioId = :userId ORDER BY fecha DESC")
    fun getByMateria(materiaId: Int, userId: Int): Flow<List<ImagenEntity>>

    @Query("SELECT * FROM imagenes WHERE materiaId = :materiaId AND usuarioId = :userId ORDER BY fecha DESC")
    suspend fun getByMateriaOnce(materiaId: Int, userId: Int): List<ImagenEntity>


    @Query("SELECT * FROM imagenes WHERE usuarioId = :userId ORDER BY fecha DESC")
    fun getAllByUsuario(userId: Int): Flow<List<ImagenEntity>>

    @Query("SELECT * FROM imagenes WHERE id = :id")
    suspend fun getById(id: Int): ImagenEntity?

    @Insert(onConflict = OnConflictStrategy.REPLACE)
    suspend fun insert(imagen: ImagenEntity)

    @Insert(onConflict = OnConflictStrategy.REPLACE)
    suspend fun insertAndReturnId(imagen: ImagenEntity): Long

    @Insert(onConflict = OnConflictStrategy.REPLACE)
    suspend fun insertAll(imagenes: List<ImagenEntity>)

    @Query("DELETE FROM imagenes WHERE usuarioId = :userId")
    suspend fun deleteAllByUsuario(userId: Int)

    @Query("DELETE FROM imagenes WHERE materiaId = :materiaId AND usuarioId = :userId")
    suspend fun deleteByMateriaAndUsuario(materiaId: Int, userId: Int)

    @Update
    suspend fun update(imagen: ImagenEntity)

    @Query("SELECT * FROM imagenes WHERE remoteId = :remoteId LIMIT 1")
    suspend fun getByRemoteId(remoteId: Int): ImagenEntity?

    @Query("UPDATE imagenes SET nota = :nota WHERE id = :id")
    suspend fun updateNota(id: Int, nota: String)

    @Query("UPDATE imagenes SET favorita = :favorita WHERE id = :id")
    suspend fun toggleFavorita(id: Int, favorita: Boolean)

    @Query("DELETE FROM imagenes WHERE id = :id")
    suspend fun deleteById(id: Int)
}

package com.example.organizadoracademico.data.local.dao

import androidx.room.Dao
import androidx.room.Insert
import androidx.room.OnConflictStrategy
import androidx.room.Query
import com.example.organizadoracademico.data.local.entities.SyncQueueEntity

@Dao
interface SyncQueueDao {

    @Insert(onConflict = OnConflictStrategy.REPLACE)
    suspend fun insert(item: SyncQueueEntity)

    @Query("SELECT * FROM sync_queue ORDER BY createdAt ASC LIMIT :limit")
    suspend fun getPending(limit: Int = 50): List<SyncQueueEntity>

    @Query("DELETE FROM sync_queue WHERE id = :id")
    suspend fun deleteById(id: Int)

    @Query("DELETE FROM sync_queue WHERE entityType = :entityType AND entityLocalId = :entityLocalId")
    suspend fun deleteByEntity(entityType: String, entityLocalId: Int)

    @Query("UPDATE sync_queue SET retryCount = retryCount + 1 WHERE id = :id")
    suspend fun incrementRetry(id: Int)
}

